                <div className="space-y-2">
                  <label htmlFor="resolution" className="text-sm font-medium text-slate-300">Resolução (Tamanho)</label>
                  <select 
                    id="resolution"
                    value={resolution}
                    onChange={(e) => {
                        setResolution(e.target.value as '1K' | '2K' | '4K');
